tinymce.PluginManager.add('multimedia', function(editor, url) {
    editor.ui.registry.addIcon('multimedia', '<?xml version="1.0" encoding="utf-8"?>\n' +
        '<!-- Generator: Adobe Illustrator 16.0.0, SVG Export Plug-In . SVG Version: 6.00 Build 0)  -->\n' +
        '<!DOCTYPE svg PUBLIC "-//W3C//DTD SVG 1.1//EN" "http://www.w3.org/Graphics/SVG/1.1/DTD/svg11.dtd">\n' +
        '<svg version="1.1" id="Layer_1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" x="0px" y="0px"\n' +
        '\t width="24px" height="17px" viewBox="0 0 24 17" enable-background="new 0 0 24 17" xml:space="preserve">\n' +
        '<g>\n' +
        '\t<polygon fill-rule="evenodd" clip-rule="evenodd" points="22.074,15.055 19.038,9.994 17.012,12.019 12.962,6.958 9.926,15.055 \t\n' +
        '\t\t"/>\n' +
        '\t<path fill-rule="evenodd" clip-rule="evenodd" d="M13,4V0H4v11.409C3.581,11.156,3.065,11,2.5,11C1.119,11,0,11.896,0,13\n' +
        '\t\ts1.119,2,2.5,2c0.923,0,1.72-0.404,2.153-1H5V3h7v1H8v13h16V4H13z M5,2V1h7v1H5z M23.086,16.068H8.914V4.932h14.173V16.068z"/>\n' +
        '\t<path fill-rule="evenodd" clip-rule="evenodd" d="M12.642,8.048h0.019H12.642z"/>\n' +
        '\t<circle fill-rule="evenodd" clip-rule="evenodd" cx="20.5" cy="7.5" r="1.5"/>\n' +
        '</g>\n' +
        '</svg>');

    var openDialog = function () {
        var cid = editor.getParam('content_id');
        var ctype = editor.getParam('content_type');
        var module_code = editor.getParam('module_code');
        var query = '?cid='+cid+'&ctype='+ctype+'&moduleCode='+module_code;
        return editor.windowManager.openUrl({
            url: tinymce.baseURL + '/plugins/multimedia/scripts/multimedia.php'+query,
            title: 'Multimedia',
            width: 740,
            height: 475,
        });
    };

    editor.ui.registry.addButton('multimedia', {
        tooltip: 'Multimedia',
        icon: 'multimedia',
        onAction: function () {
            // Open window
            openDialog();
        }

    });

    // Adds a menu item, which can then be included in any menu via the menu/menubar configuration
    editor.ui.registry.addMenuItem('multimedia', {
        text: 'Multimedia',
        icon: 'multimedia',
        onAction: function () {
            // Open window
            openDialog();
        }
    });
});